  3â†’/*
  4â†’  Handle image resizing if the image exceeds the window dimensions.
  5â†’
  6â†’  If we are using the Chrome engine, add the "chrome" class to the
  7â†’  body and defer image resizing to pure CSS. The Chrome engine can
  8â†’  handle image resizing on its own, but for older versions of WebView,
  9â†’  we do it here.
 10â†’
 11â†’  If we are resizing with JavaScript, we also account for the CSS zoom
 12â†’  level applied to the image. If an image is scaled with CSS zoom, the
 13â†’  dimensions given to us by the browser will not be scaled
 14â†’  accordingly, giving us only the original dimensions. We have to
 15â†’  fetch the zoom value and scale the dimensions with it before
 16â†’  checking if the image exceeds the window bounds.
 17â†’
 18â†’  If the WebView loads too early on Android <= 2.3 (which happens on
 19â†’  the first card or regularly with WebView switching enabled), then
 20â†’  the window dimensions returned to us are 0x0. In this case, we skip
 21â†’  image resizing and try again after we know the window has fully
 22â†’  loaded with a method call initiated from Java (onPageFinished).
 23â†’*/
 24â†’var resizeImages = function () {
 25â†’    if (navigator.userAgent.indexOf("Chrome") > -1) {
 26â†’        document.body.className = document.body.className + " chrome";
 27â†’    } else {
 28â†’        if (window.innerWidth === 0 || window.innerHeight === 0) {
 29â†’            return;
 30â†’        }
 31â†’        var maxWidth = window.innerWidth * 0.9;
 32â†’        var maxHeight = window.innerHeight * 0.9;
 33â†’        var ratio = 0;
 34â†’        var images = document.getElementsByTagName("img");
 35â†’        for (var i = 0; i < images.length; i++) {
 36â†’            var img = images[i];
 37â†’            var scale = 1;
 38â†’            var zoom = window.getComputedStyle(img).getPropertyValue("zoom");
 39â†’            if (!isNaN(zoom)) {
 40â†’                scale = zoom;
 41â†’            }
 42â†’            var width = img.width * scale;
 43â†’            var height = img.height * scale;
 44â†’            if (width > maxWidth) {
 45â†’                img.width = maxWidth;
 46â†’                img.height = height * (maxWidth / width);
 47â†’                width = img.width;
 48â†’                height = img.height;
 49â†’                img.style.zoom = 1;
